Context-Specific Models: The Same Word, Different Classes
LetвҖҷs make the вҖңdifferent Product in each contextвҖқ idea concrete:
Catalog Context вҖ” CatalogProduct
typescript
// catalog/domain/catalog-product.entity.ts
import { ProductId, Money } from '@shopflow/shared-kernel';export interface ProductVariant {
variantId: string;
color: string;
size: string;
price: Money;
stockCount: number;
}export interface ProductReviewSummary {
averageRating: number;
totalReviews: number;
}export class CatalogProduct {
constructor(
readonly id: ProductId,
readonly name: string,
readonly description: string,
readonly category: string,
readonly variants: readonly ProductVariant[],
readonly imageUrls: readonly string[],
readonly reviewSummary: ProductReviewSummary,
readonly isActive: boolean,
) {} get lowestPrice(): Money {
const prices = this.variants.map(v => v.price.amountInMinorUnits);
const lowest = Math.min(...prices);
const variant = this.variants.find(v => v.price.amountInMinorUnits === lowest)!;
return variant.price;
} get hasMultipleVariants(): boolean {
return this.variants.length > 1;
} get isAvailable(): boolean {
return this.isActive && this.variants.some(v => v.stockCount > 0);
} findVariant(variantId: string): ProductVariant | undefined {
return this.variants.find(v => v.variantId === variantId);
}
}Cart Context вҖ” CartProduct (a reference, not a catalog)
typescript
// cart/domain/cart-product-ref.value-object.ts
// In the Cart context, "Product" is just a reference snapshot.
// We don't need the full catalog data вҖ” just what we need to display the cart.
import { ProductId, Money } from '@shopflow/shared-kernel';export class CartProductRef {
constructor(
readonly productId: ProductId,
readonly variantId: string,
readonly name: string, // Snapshot at time of adding
readonly variantDescription: string, // e.g., "Blue / Large"
readonly unitPrice: Money, // Snapshot at time of adding
readonly imageUrl: string,
) {} // No catalog methods here вҖ” no isAvailable, no variants list
// This context only cares about what was added and at what price
}Orders Context вҖ” OrderLineItem (a historical record)
typescript
// orders/domain/order-line-item.entity.ts
import { ProductId, Money } from '@shopflow/shared-kernel';export class OrderLineItem {
constructor(
readonly lineItemId: string,
readonly productId: ProductId, // For linking back to catalog
readonly productName: string, // Frozen at time of purchase
readonly variantDescription: string,
readonly sku: string,
readonly unitPricePaid: Money, // Never changes
readonly quantity: number,
readonly totalPricePaid: Money,
) {} // Order line items are immutable вҖ” no mutation methods
// Business logic here is about the historical record
get formattedTotal(): string {
return this.totalPricePaid.format();
}
}This is not duplication вҖ” this is appropriate isolation. Each context owns exactly the data it needs and no more. If the Catalog context adds a new field (sustainabilityRating), the Cart and Orders contexts are not affected. If the Orders context needs to add returnEligible, it doesn't affect the catalog.

